{"title":"ptp-vis-v6","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "description": "PTP Topology",
  "autosize": pad,
  "padding": 50,

  "signals": [
    { "name": "TREE_Y_OFFSET", "value": 50 },
    { "name": "LABEL_COLOR", "value": "#fff" },
    { "name": "LABEL_DY_FACTOR", "value": 1.2 },
    { "name": "LAYER_SPACING", "value": 180 },

    // -- COLORS: status and link states --
    { "name": "CONVERGED_COLOR", "value": "#ccc" },
    { "name": "UNCONVERGED_COLOR", "value": "#d73027" },
    { "name": "UNCONVERGED_FLASH_COLOR", "value": "#ffffff" },
    { "name": "SIDE_RED_COLOR",   "value": "#e91e63" },
    { "name": "SIDE_BLUE_COLOR",  "value": "#1f77b4" },
    { "name": "SIDE_MIXED_COLOR", "value": "#9c27b0" },
    { "name": "STATUS_OK_COLOR", "value": "#41ab5d" },
    { "name": "GM_OK_COLOR", "value": "#006d2c" },
    { "name": "PASSIVE_COLOR", "value": "#ff7f00" },
    // Build 74: amber stroke for slave edges where the host disagrees with its master's majority GM.
    { "name": "MINORITY_GM_COLOR", "value": "#FFC107" },
    // Build 75: white flash partner so minority edges & masters blink like PORT_DOWN / UNCONVERGED.
    { "name": "MINORITY_GM_FLASH_COLOR", "value": "#ffffff" },
    { "name": "NO_DATA_COLOR_ON", "value": "#bbbbbb" },
    { "name": "NO_DATA_COLOR_OFF", "value": "#555555" },

    // -- PORT DOWN: aggregation-switch port-operation-status signalling --
    // Note: sdvn index semantics are INVERTED from SNMP ifOperStatus —
    //   i_value === 1 means DOWN, 0 means UP. Hard-coded here for clarity.
    { "name": "PORT_DOWN_COLOR",       "value": "#ff00ff" },
    { "name": "PORT_DOWN_FLASH_COLOR", "value": "#ffffff" },
    { "name": "PORT_DOWN_VALUE",       "value": 1 },

    // -- ANIMATION: blink toggle for missing-data indicator --
    {
      "name": "blink",
      "value": true,
      "on": [
        {"events": {"type": "timer", "throttle": 800}, "update": "!blink"}
      ]
    },

    { "name": "labels", "value": true },
    { "name": "layout", "value": "tidy" },
    { "name": "links", "value": "diagonal" },
    { "name": "pan_speed_multiplier", "value": 0.75 },
    { "name": "LEFT_PADDING", "value": 50,}

    { "name": "GM_SPACING","value": 80,},
    {"name": "MASTER_SPACING","update": "40 / max(zoom, 0.05)",},

    {
      "name": "zipper_lanes",
      "value": 1,
      "bind": {"input": "range", "min": 1, "max": 4, "step": 1, "name": "Followers per Row: "}
    },
    {
      "name": "zipper_offset",
      "value": 20,
      "bind": {"input": "range", "min": 10, "max": 50, "step": 5, "name": "Follower Spacing: "}
    },
    {
      "name": "GROUP_PADDING",
      "value": 30,
      "bind": {"input": "range", "min": 0, "max": 150, "step": 5, "name": "Group Gap: "}
    },
    {
      "name": "hideDirectGmSlaves",
      "value": false,
      "bind": {"input": "checkbox", "name": "Hide direct-to-GM slaves"}
    }

    // -- INTERACTIVITY: pan, zoom, hover --

    // PAN: drag to scroll the canvas

    {
      "name": "down",
      "value": null,
      // Captures mouse events
      "on": [
        {"events": "pointerup, mouseup", "update": "null"},
        {
          "events": "pointerdown",
          // If clicking a symbol, set it to null to avoid slipping
          // xy() instantly returns the current coordinate.
          // tldr if clicking a valid area, return coords as array.
          "update": "(event.item && event.item.mark.name === 'node_symbols') ? null : xy()"
        }
      ]
    },
    {
      "name": "pan_base_x",
      "value": 0,
      "on": [{"events": "pointerdown", "update": "tx"}]
    },
    {
      "name": "pan_base_y",
      "value": 0,
      "on": [{"events": "pointerdown", "update": "ty"}]
    },
    {
      "name": "delta",
      "value": [0, 0],
      "on": [{"events": [{"source": "window", "type": "pointermove", "consume": true, "between": [{"type": "pointerdown"}, {"source": "window", "type": "pointerup"}]}
      ], 
      // Calculates the diff between 
      "update": "down ? [down[0]-x(), down[1]-y()] : [0,0]"}]
    },

    // ZOOM: scroll wheel toward cursor; zoom-out re-centers on canvas
    {

      "name": "anchor", 
      "value": [0, 0], 
      "on": [
        {
          "events": "wheel!",
          // If zooming in (less than 0), zoom towards cursor
          // If zooming out, zoom towards the center (width/2, height/2)
          "update": "event.deltaY < 0 ? [x(), y()] : [width/2, height/2]" 
        },
      ]
    },
    {
      "name": "zoom_factor", 
      "value": 1, 
      "on": [
        {
          "events": "wheel!",
          "force": true,
          // Return 1 if trying to zoom past 100 or below 0.2, blocking further zoom inputs.
          // Otherwise, apply smoothing

          // Browser returns deltaMode (0 for pixels, 1 for lines)
          // Applying pow(16) on the deltamode normalizes everything to pixels
          // 1.001 is the exponential growth of each zoom interval so it is smooth relative
          // to the current size.

          "update": "((zoom >= 100 && event.deltaY < 0) || (zoom <= 0.2 && event.deltaY > 0)) ? 1 : pow(1.001, event.deltaY * pow(16, event.deltaMode))"
        }
      ]
    },
    {
      // Track zoom state in zoom_factor signal
      "name": "zoom", 
      "value": 1, 
      "on": [{"events": {"signal": "zoom_factor"}, "update": "clamp(zoom / zoom_factor, 0.2, 100)"}]
    },
    {
      "name": "tx", 
      "value": 0, 
      "on": [
        {"events": {"signal": "delta"}, "update": "pan_base_x - delta[0] * pan_speed_multiplier"}, 
        // Transformation, calculates the distance between chart edge and the mouse (anchor)
        // Scale the distance based on how much zoom just changed, and then add the scaled distance back to the mouse position.
        // This basically updates the chart position while it is scaling, making it look like focalized zoom.
        {"events": {"signal": "zoom_factor"}, "update": "anchor[0] + (tx - anchor[0]) / zoom_factor"}
      ]
    },
    {
      "name": "ty", 
      "value": 0, 
      "on": [
        {"events": {"signal": "delta"}, "update": "pan_base_y - delta[1] * pan_speed_multiplier"}, 
        {"events": {"signal": "zoom_factor"}, "update": "anchor[1] + (ty - anchor[1]) / zoom_factor"}
      ]
    },
    {
      "name": "hover", 
      "value": null, 
      "on": [
        {"events": "symbol:mouseover", "update": "datum"},
        {"events": "symbol:mouseout", "update": "null"},
        {"events": "wheel, mousedown", "update": "null"}
      ]
    },
    // TOOLTIP: builds a string array for hover display
    // Structure: grandmaster -> master -> slave, with optional port-state rows.
    {
      "name": "tooltip_data",
      "update": "hover ? (hover.type === 'grandmaster' ? (hover.has_no_port_data ? ['Device: ' + hover.display_name, 'Role: ' + hover.type, 'Status: ' + (hover.is_passive ? 'Passive' : (hover.status_value === 1 ? 'Unconverged Followers' : 'No unconverged followers')), 'Error: No port data available', '---', 'Port 1: ' + (hover.clock_data ? hover.clock_data.port_1 : 'NO DATA'), 'Port 2: ' + (hover.clock_data ? hover.clock_data.port_2 : 'NO DATA'), 'Port 3: ' + (hover.clock_data ? hover.clock_data.port_3 : 'NO DATA'), 'Port 4: ' + (hover.clock_data ? hover.clock_data.port_4 : 'NO DATA')] : ['Device: ' + hover.display_name, 'Role: ' + hover.type, 'Status: ' + (hover.is_passive ? 'Passive' : (hover.status_value === 1 ? 'Unconverged Followers' : 'No unconverged followers')), '---', 'Port 1: ' + (hover.clock_data ? hover.clock_data.port_1 : 'NO DATA'), 'Port 2: ' + (hover.clock_data ? hover.clock_data.port_2 : 'NO DATA'), 'Port 3: ' + (hover.clock_data ? hover.clock_data.port_3 : 'NO DATA'), 'Port 4: ' + (hover.clock_data ? hover.clock_data.port_4 : 'NO DATA')]) : (hover.type === 'master' ? (hover.has_no_port_data ? ['Device: ' + hover.display_name, 'Role: ' + hover.type, 'Status: ' + (hover.is_passive ? 'Passive' : (hover.status_value === 1 ? 'Unconverged Followers' : 'No unconverged followers')), 'Connected To: ' + hover.parent, (hover.total_count != null && hover.total_count > hover.majority_count ? 'GM dissent: ' + (hover.total_count - hover.majority_count) + ' of ' + hover.total_count + ' hosts disagree' : ''), 'Error: No port data available', '---', 'Port 1: ' + (hover.clock_data ? hover.clock_data.port_1 : 'NO DATA'), 'Port 2: ' + (hover.clock_data ? hover.clock_data.port_2 : 'NO DATA'), 'Port 3: ' + (hover.clock_data ? hover.clock_data.port_3 : 'NO DATA'), 'Port 4: ' + (hover.clock_data ? hover.clock_data.port_4 : 'NO DATA')] : ['Device: ' + hover.display_name, 'Role: ' + hover.type, 'Status: ' + (hover.is_passive ? 'Passive' : (hover.status_value === 1 ? 'Unconverged Followers' : 'No unconverged followers')), 'Connected To: ' + hover.parent, (hover.total_count != null && hover.total_count > hover.majority_count ? 'GM dissent: ' + (hover.total_count - hover.majority_count) + ' of ' + hover.total_count + ' hosts disagree' : ''), '---', 'Port 1: ' + (hover.clock_data ? hover.clock_data.port_1 : 'NO DATA'), 'Port 2: ' + (hover.clock_data ? hover.clock_data.port_2 : 'NO DATA'), 'Port 3: ' + (hover.clock_data ? hover.clock_data.port_3 : 'NO DATA'), 'Port 4: ' + (hover.clock_data ? hover.clock_data.port_4 : 'NO DATA')]) : ['Device: ' + hover.device_name, 'Type: ' + (hover.device_type || 'Unknown Device'), 'Role: ' + hover.type, 'ID: ' + hover.id, 'Status: ' + hover.final_status, 'Connected To: ' + hover.parent, (hover.gm_id ? 'Reported GM: ' + hover.gm_id : '')])) : []"
    },
    {"name": "show_master_labels", "update": "zoom > 1.5"},
    {"name": "show_slave_labels", "update": "zoom > 25"}
  ],

  "data": [
    // -- MANUAL NAMES: device name + group + role overrides --
    {
      "name": "manual_names",
      "values": [
        {"ids": [{"mac": "00-02-C5-FF-FE-24-0B-3C", "side": "RED"}, {"mac": "00-02-C5-FF-FE-24-0B-3D", "side": "BLUE"}], "name": "7N.MSC.003.GM.A", "group_id": "GM", "role": "grandmaster"},
        {"ids": [{"mac": "00-02-C5-FF-FE-24-0B-4E", "side": "RED"}, {"mac": "00-02-C5-FF-FE-24-0B-4F", "side": "BLUE"}], "name": "7N.MSC.003.GM.B", "group_id": "GM", "role": "grandmaster"},
        {"ids": [{"mac": "00-02-C5-FF-FE-24-0B-12", "side": "RED"}, {"mac": "00-02-C5-FF-FE-24-0B-13", "side": "BLUE"}], "name": "7N.MSC.027.GM.C", "group_id": "GM", "role": "grandmaster"},
        {"ids": [{"mac": "00-02-C5-FF-FE-24-0B-60", "side": "RED"}, {"mac": "00-02-C5-FF-FE-24-0B-61", "side": "BLUE"}], "name": "7N.MSC.027.GM.D", "group_id": "GM", "role": "grandmaster"},

        {"ids": [{"mac": "00-02-C5-FF-FE-24-0B-5A", "side": "RED"}, {"mac": "00-02-C5-FF-FE-24-0B-5B", "side": "BLUE"}], "name": "7N.MSC.079.BC.A", "group_id": "7N-BC-1", "role": "master"},
        {"ids": [{"mac": "00-02-C5-FF-FE-24-0B-2A", "side": "RED"}, {"mac": "00-02-C5-FF-FE-24-0B-2B", "side": "BLUE"}], "name": "7N.MSC.079.BC.B", "group_id": "7N-BC-1", "role": "master"},

        {"ids": [{"mac": "00-02-C5-FF-FE-2A-85-08", "side": "RED"}, {"mac": "00-02-C5-FF-FE-2A-85-09", "side": "BLUE"}], "name": "7N.MSC.079.BC.C", "group_id": "7N-BC-2", "role": "master"},
        {"ids": [{"mac": "00-02-C5-FF-FE-2A-75-04", "side": "RED"}, {"mac": "00-02-C5-FF-FE-2A-75-05", "side": "BLUE"}], "name": "7N.MSC.079.BC.D", "group_id": "7N-BC-2", "role": "master"},

        {"ids": [{"mac": "00-02-C5-FF-FE-2D-7F-D9", "side": "RED"}, {"mac": "00-02-C5-FF-FE-2D-7F-DA", "side": "BLUE"}], "name": "7N.MSC.003.BC.E", "group_id": "7N-BC-3", "role": "master"},
        {"ids": [{"mac": "00-02-C5-FF-FE-2D-82-DB", "side": "RED"}, {"mac": "00-02-C5-FF-FE-2D-82-DC", "side": "BLUE"}], "name": "7N.MSC.027.BC.E", "group_id": "7N-BC-3", "role": "master"},

        {"ids": [{"mac": "00-02-C5-FF-FE-32-DE-9F", "side": "RED"}, {"mac": "00-02-C5-FF-FE-32-DE-A0", "side": "BLUE"}], "name": "7N.MSC.003.BC.F", "group_id": "7N-BC-4", "role": "master"},
        {"ids": [{"mac": "00-02-C5-FF-FE-32-DF-89", "side": "RED"}, {"mac": "00-02-C5-FF-FE-32-DF-8A", "side": "BLUE"}], "name": "7N.MSC.027.BC.F", "group_id": "7N-BC-4", "role": "master"},

        {"ids": [{"mac": "00-02-C5-FF-FE-20-33-6A", "side": "RED"}, {"mac": "00-02-C5-FF-FE-20-33-6B", "side": "BLUE"}], "name": "7N.MSC.003.BC.G", "group_id": "7N-BC-5", "role": "master"},
        {"ids": [{"mac": "00-02-C5-FF-FE-33-77-D7", "side": "RED"}, {"mac": "00-02-C5-FF-FE-33-77-D8", "side": "BLUE"}], "name": "7N.MSC.027.BC.G", "group_id": "7N-BC-5", "role": "master"},

        {"ids": [{"mac": "00-02-C5-FF-FE-3F-D7-44", "side": "RED"}, {"mac": "00-02-C5-FF-FE-3F-D7-45", "side": "BLUE"}], "name": "7S-MSC-068A-GM-A", "group_id": "7SGM", "role": "grandmaster"},
        {"ids": [{"mac": "00-02-C5-FF-FE-3F-D7-80", "side": "RED"}, {"mac": "00-02-C5-FF-FE-3F-D7-81", "side": "BLUE"}], "name": "7S-MSC-068A-GM-B", "group_id": "7SGM", "role": "grandmaster"},

        {"ids": [{"mac": "00-02-C5-FF-FE-24-0B-84", "side": "RED"}], "name": "SEC-A", "group_id": "SEC"},

        // -- AGGREGATION SWITCHES: non-PTP devices in-path between GM and BCs.
        //    Joined by annotation.general.device_name from log-metric-m-sdvn-*.
        //    `side` ("RED" | "BLUE") pins the switch to a fabric — masters
        //    whose MAC side matches will be re-parented onto this agg.
        //    Declare one entry per side for a RED/BLUE pair; both share
        //    `group_id` and `gm_group_id`, only `name` and `side` differ.
        //    `neighbor` names must match other manual_names.name values exactly.
        //    Omit `neighbor` (or leave null) to fall back to node-level flash.
        {
          "name": "7S-AGG-A",
          "role": "aggregation",
          "side": "RED",
          "group_id": "7S-BC-1",
          "gm_group_id": "7SGM",
          "upstream_ports":   [{"port": 1, "neighbor": "7S-MSC-068A-GM-A", "mac": "00:0b:ab:00:00:a1"},
                               {"port": 2, "neighbor": "7S-MSC-068A-GM-B", "mac": "00:0b:ab:00:00:a2"}],
          "downstream_ports": [{"port": 3, "neighbor": "7S-BC-1-A"},
                               {"port": 4, "neighbor": "7S-BC-1-B"}]
        },
        {
          "name": "7S-AGG-B",
          "role": "aggregation",
          "side": "BLUE",
          "group_id": "7S-BC-1",
          "gm_group_id": "7SGM",
          "upstream_ports":   [{"port": 1, "neighbor": "7S-MSC-068A-GM-A", "mac": "00:0b:ab:00:00:b1"},
                               {"port": 2, "neighbor": "7S-MSC-068A-GM-B", "mac": "00:0b:ab:00:00:b2"}],
          "downstream_ports": [{"port": 3, "neighbor": "7S-BC-1-A"},
                               {"port": 4, "neighbor": "7S-BC-1-B"}]
        },
              ]
    },
    {
      "name": "manual_names_flat",
      "source": "manual_names",
      "transform": [
        // Coalesce missing `ids` to [] so entries without MAC IDs
        // (e.g. aggregation switches) don't blow up the flatten.
        {"type": "formula", "as": "ids", "expr": "isArray(datum.ids) ? datum.ids : []"},
        {"type": "filter", "expr": "length(datum.ids) > 0"},
        {"type": "flatten", "fields": ["ids"], "as": ["id"]},
        {"type": "formula", "as": "id_mac",  "expr": "datum.id && datum.id.mac  ? datum.id.mac  : datum.id"},
        {"type": "formula", "as": "id_side", "expr": "datum.id && datum.id.side ? datum.id.side : null"}
      ]
    },


    // -- MAC INVENTORY: maps port MACs to device names -- â€” maps port MACs to parent device names
    {
      "name": "mac_inventory",
      "url": {
        "%timefield%": "",
        "index": "mac-inventory-results",
        "body": {
          "size": 10000,
          "sort": [{"@timestamp": "desc"}],
          "_source": ["mac_address", "annotation.general.device_name", "host.ip"]
        }
      },
      "format": {"type": "json"},
      "transform": [
        // Safe-load: tolerate missing/empty mac-inventory-results index.
        // Coalesce hits.hits to [] so flatten produces 0 rows instead of
        // failing dataset construction (which would cascade through every
        // lookup in source_hits and ultimately leave tree undefined).
        {"type": "formula", "as": "_hits",
          "expr": "datum.hits && datum.hits.hits ? datum.hits.hits : []"},
        {"type": "flatten", "fields": ["_hits"], "as": ["_hit"]},
        {"type": "formula", "as": "_source", "expr": "datum._hit && datum._hit._source ? datum._hit._source : null"},
        {"type": "formula", "as": "mac",          "expr": "datum._source && datum._source.mac_address ? lower(replace(datum._source.mac_address, '-', ':')) : null"},
        {"type": "formula", "as": "inv_dev_name", "expr": "(datum._source && datum._source.annotation && datum._source.annotation.general && datum._source.annotation.general.device_name) ? datum._source.annotation.general.device_name : (datum._source && datum._source.host ? datum._source.host.ip : (datum._source ? datum._source['host.ip'] : null))"}
      ]
    },
    {
      "name": "filter_probe_ptp",
      "url": {
        "%context%": true,
        "%timefield%": "@timestamp",
        "index": "log-metric-p-ptpmetrics-*",
        "body": {
          "size": 0,
          "aggs": {
            "by_ip": {"terms": {"field": "host.ip", "size": 10000}}
          }
        }
      },
      "format": {"property": "aggregations.by_ip.buckets"}
    },
    // -- ELASTICSEARCH: latest PTP metrics per device --
    // Extract the fields I need
    {
      "name": "source_hits",
      "url": {
        "%timefield%": "@timestamp",
        "index": "log-metric-p-ptpmetrics-*",
        "body": {
          "size": 0, // We only care about the aggregation result
          "aggs": {
            "by_device": {
              "terms": {
                "field": "host.ip",
                "size": 3000
              },
              "aggs": {
                "latest_log": {
                  "top_hits": {
                    "size": 1,
                    "sort": [{"@timestamp": {"order": "desc"}}]
                  }
                }
              }
            }
          }
        }
      },
      "format": {"property": "aggregations.by_device.buckets"},
      "transform": [
        // 0. Extract the latest source document from the top hit
        {
          "type": "formula",
          "as": "_source",
          "expr": "datum.latest_log.hits.hits[0]._source"
        },

        // 1. Extract raw MACs from that latest source
        {
          "type": "formula", 
          "as": "raw_master_mac", 
          "expr": "datum._source.ptpmetrics && datum._source.ptpmetrics.ptpstatus ? datum._source.ptpmetrics.ptpstatus.s_master_identity : null"
        },
        {
          "type": "formula", 
          "as": "raw_gm_mac", 
          "expr": "datum._source.ptpmetrics && datum._source.ptpmetrics.ptpstatus ? datum._source.ptpmetrics.ptpstatus.s_grandmaster_identity : null"
        },
        {
          "type": "formula", 
          "as": "raw_master_mac", 
          "expr": "datum.raw_master_mac && test(/^0[xX]/, datum.raw_master_mac) && length(datum.raw_master_mac) == 18 ? upper(substring(datum.raw_master_mac, 2, 4)) + '-' + upper(substring(datum.raw_master_mac, 4, 6)) + '-' + upper(substring(datum.raw_master_mac, 6, 8)) + '-' + upper(substring(datum.raw_master_mac, 8, 10)) + '-' + upper(substring(datum.raw_master_mac, 10, 12)) + '-' + upper(substring(datum.raw_master_mac, 12, 14)) + '-' + upper(substring(datum.raw_master_mac, 14, 16)) + '-' + upper(substring(datum.raw_master_mac, 16, 18)) : datum.raw_master_mac"
        },
        {
          "type": "formula", 
          "as": "raw_gm_mac", 
          "expr": "datum.raw_gm_mac && test(/^0[xX]/, datum.raw_gm_mac) && length(datum.raw_gm_mac) == 18 ? upper(substring(datum.raw_gm_mac, 2, 4)) + '-' + upper(substring(datum.raw_gm_mac, 4, 6)) + '-' + upper(substring(datum.raw_gm_mac, 6, 8)) + '-' + upper(substring(datum.raw_gm_mac, 8, 10)) + '-' + upper(substring(datum.raw_gm_mac, 10, 12)) + '-' + upper(substring(datum.raw_gm_mac, 12, 14)) + '-' + upper(substring(datum.raw_gm_mac, 14, 16)) + '-' + upper(substring(datum.raw_gm_mac, 16, 18)) : datum.raw_gm_mac"
        },

        // 2. Lookup the Device Name from the manual_names list
        {"type": "lookup", "from": "manual_names_flat", "key": "id_mac", "fields": ["raw_master_mac"], "as": ["master_lookup"]},
        {"type": "lookup", "from": "manual_names_flat", "key": "id_mac", "fields": ["raw_gm_mac"], "as": ["gm_lookup"]},
        // Scalar side tag for use past the tree aggregate (which drops master_lookup)
        {"type": "formula", "as": "reported_master_side", "expr": "datum.master_lookup && datum.master_lookup.id_side ? datum.master_lookup.id_side : null"},
        // Slave-reported GM side — used to derive a master node's upstream side (masters are synthetic from slave data)
        {"type": "formula", "as": "reported_gm_side", "expr": "datum.gm_lookup && datum.gm_lookup.id_side ? datum.gm_lookup.id_side : null"},
        // Per-row unconverged flag so masters/GMs can roll up any-unconverged-descendant counts via sum.
        {"type": "formula", "as": "is_unconverged", "expr": "datum.status_value === 1 ? 1 : 0"},
        // 3. Normalise EUI-64 clock identity to 6-byte colon MAC for inventory lookup
        {"type": "formula", "as": "mac_norm_master", "expr": "datum.raw_master_mac ? (length(datum.raw_master_mac) > 17 ? lower(substring(datum.raw_master_mac,0,2))+':'+lower(substring(datum.raw_master_mac,3,5))+':'+lower(substring(datum.raw_master_mac,6,8))+':'+lower(substring(datum.raw_master_mac,15,17))+':'+lower(substring(datum.raw_master_mac,18,20))+':'+lower(substring(datum.raw_master_mac,21,23)) : lower(replace(datum.raw_master_mac, '-', ':'))) : null"},
        {"type": "formula", "as": "mac_norm_gm",     "expr": "datum.raw_gm_mac ? (length(datum.raw_gm_mac) > 17 ? lower(substring(datum.raw_gm_mac,0,2))+':'+lower(substring(datum.raw_gm_mac,3,5))+':'+lower(substring(datum.raw_gm_mac,6,8))+':'+lower(substring(datum.raw_gm_mac,15,17))+':'+lower(substring(datum.raw_gm_mac,18,20))+':'+lower(substring(datum.raw_gm_mac,21,23)) : lower(replace(datum.raw_gm_mac, '-', ':'))) : null"},
        {"type": "lookup", "from": "mac_inventory", "key": "mac", "fields": ["mac_norm_master"], "as": ["master_inv_lookup"]},
        {"type": "lookup", "from": "mac_inventory", "key": "mac", "fields": ["mac_norm_gm"],     "as": ["gm_inv_lookup"]},

        // 3. Set the official IDs to the Name (if found), otherwise fallback to MAC
        {"type": "formula", "as": "master_id", "expr": "datum.master_lookup ? datum.master_lookup.name : (datum.master_inv_lookup && datum.master_inv_lookup.inv_dev_name ? datum.master_inv_lookup.inv_dev_name : datum.raw_master_mac)"},
        {"type": "formula", "as": "gm_id", "expr": "datum.gm_lookup ? datum.gm_lookup.name : (datum.gm_inv_lookup && datum.gm_inv_lookup.inv_dev_name ? datum.gm_inv_lookup.inv_dev_name : datum.raw_gm_mac)"},

        // 4. Map existing formulas to the latest source
        {"type": "formula", "as": "slave_id", "expr": "datum.key"}, // The bucket key is the host.ip

        {"type": "formula", "as": "ptp_status", "expr": "datum._source.ptpmetrics && datum._source.ptpmetrics.ptpstatus ? datum._source.ptpmetrics.ptpstatus.s_ptp_status : 'Unknown'"},

        {"type": "formula", "as": "status_value", "expr": "datum.ptp_status !== 'Converged' && datum.ptp_status !== 'Locked' ? 1 : 0"},

        // Grab device metadata from the latest hit
        {"type": "formula", "as": "device_name", "expr": "datum._source.annotation && datum._source.annotation.general ? datum._source.annotation.general.device_name : null"},

        {"type": "formula", "as": "device_type", "expr": "datum._source.annotation && datum._source.annotation.general ? datum._source.annotation.general.device_type : null"},

        {"type": "filter", "expr": "datum.master_id != null"}
      ]
    },
    // count host-reports per (master_id, gm_id) so we can pick the majority GM downstream.
    {
      "name": "master_gm_counts",
      "source": "source_hits",
      "transform": [
        {"type": "filter", "expr": "datum.master_id != null && datum.gm_id != null"},
        {"type": "aggregate", "groupby": ["master_id", "gm_id"], "ops": ["count"], "as": ["host_count"]}
      ]
    },
    // per master, the GM with the most host reports wins.
    {
      "name": "master_majority_gm",
      "source": "master_gm_counts",
      "transform": [
        {"type": "joinaggregate", "groupby": ["master_id"], "fields": ["host_count"], "ops": ["max"], "as": ["max_count"]},
        {"type": "joinaggregate", "groupby": ["master_id"], "fields": ["host_count"], "ops": ["sum"], "as": ["total_count"]},
        {"type": "filter", "expr": "datum.host_count === datum.max_count"},
        {"type": "aggregate", "groupby": ["master_id"], "fields": ["gm_id", "max_count", "total_count"], "ops": ["max", "max", "max"], "as": ["majority_gm_id", "majority_count", "total_count"]}
      ]
    },
    {
      "name": "clock_states",
      "url": {
        "%timefield%": "@timestamp",
        "index": "log-metric-p-msc-*", 
        "body": {
          "size": 0,
          "aggs": {
            "by_device": {
              "terms": {
                "field": "annotation.general.device_name.keyword",
                "size": 3000
              },
              "aggs": {
                "latest_log": {
                  "top_hits": {
                    "size": 1,
                    "sort": [{"@timestamp": {"order": "desc"}}],
                    "_source": [
                      "annotation.general.device_name",
                      "msc.snmp.s_port_1_state",
                      "msc.snmp.s_port_2_state",
                      "msc.snmp.s_port_3_state",
                      "msc.snmp.s_port_4_state"
                    ]
                  }
                }
              }
            }
          }
        }
      },
      "format": {"type": "json"},
      "transform": [
        // Safe-load: tolerate missing/empty log-metric-p-msc-* index.
        // Without this, a missing index trips Kibana-Vega path extraction
        // (Cannot read properties of undefined), clock_states fails to
        // build, and the lookup in the tree pipeline cascades into
        // "undefined data set name: tree".
        {"type": "formula", "as": "_buckets",
          "expr": "datum.aggregations && datum.aggregations.by_device && datum.aggregations.by_device.buckets ? datum.aggregations.by_device.buckets : []"},
        {"type": "flatten", "fields": ["_buckets"], "as": ["_bucket"]},
        {"type": "formula", "as": "key", "expr": "datum._bucket ? datum._bucket.key : null"},
        {"type": "formula", "as": "latest_log", "expr": "datum._bucket ? datum._bucket.latest_log : null"},
        {
          "type": "formula",
          "as": "_source",
          "expr": "datum.latest_log && datum.latest_log.hits && datum.latest_log.hits.hits && datum.latest_log.hits.hits[0] ? datum.latest_log.hits.hits[0]._source : null"
        },
        {
          "type": "formula", 
          "as": "device_name", 
          "expr": "datum._source && datum._source.annotation && datum._source.annotation.general ? datum._source.annotation.general.device_name : null"
        },
        {
          "type": "formula", 
          "as": "port_1", 
          "expr": "datum._source && datum._source.msc && datum._source.msc.snmp ? datum._source.msc.snmp.s_port_1_state : 'Unknown'"
        },
        {
          "type": "formula", 
          "as": "port_2", 
          "expr": "datum._source && datum._source.msc && datum._source.msc.snmp ? datum._source.msc.snmp.s_port_2_state : 'Unknown'"
        },
        {
          "type": "formula", 
          "as": "port_3", 
          "expr": "datum._source && datum._source.msc && datum._source.msc.snmp ? datum._source.msc.snmp.s_port_3_state : 'Unknown'"
        },
        {
          "type": "formula", 
          "as": "port_4", 
          "expr": "datum._source && datum._source.msc && datum._source.msc.snmp ? datum._source.msc.snmp.s_port_4_state : 'Unknown'"
        },
        {
          "type": "formula", 
          "as": "is_passive", 
          "expr": "datum.port_1 != 'PTP master' && datum.port_2 != 'PTP master' && datum.port_3 != 'PTP master' && datum.port_4 != 'PTP master'"
        }
      ]
    },

    // -- AGGREGATION STATES (raw): one-row wrapper around the full ES response.
    //    We deliberately omit format.property so that a missing/empty index does
    //    NOT trip Vega's path-extraction ("Cannot read properties of undefined").
    //    Defensive navigation is pushed down into the transforms below.
    {
      "name": "_aggregation_states_raw",
      "url": {
        "%timefield%": "@timestamp",
        "index": "log-metric-m-sdvn-*",
        "body": {
          "size": 0,
          "aggs": {
            "by_device": {
              "terms": {"field": "annotation.general.device_name.keyword", "size": 3000},
              "aggs": {
                "by_port": {
                  // ES-side bucket filter via include regex — avoids a body.query,
                  // which would clash with %timefield% in Kibana Vega.
                  "terms": {
                    "field": "sdvn.device.value.id.keyword",
                    "size": 128,
                    "include": "port-.*-operation-status"
                  },
                  "aggs": {
                    "latest": {
                      "top_hits": {
                        "size": 1,
                        "sort": [{"@timestamp": {"order": "desc"}}],
                        "_source": ["sdvn.device.value.id", "sdvn.device.value.i_value"]
                      }
                    }
                  }
                }
              }
            }
          }
        }
      },
      "format": {"type": "json"}
    },

    // -- AGGREGATION STATES: one row per (device, port) with latest port_value.
    //    Safely reshapes _aggregation_states_raw via flatten/formula chain —
    //    gracefully yields zero rows when the sdvn index has no data.
    {
      "name": "aggregation_states",
      "source": "_aggregation_states_raw",
      "transform": [
        {"type": "formula", "as": "_device_buckets",
          "expr": "datum.aggregations && datum.aggregations.by_device && datum.aggregations.by_device.buckets ? datum.aggregations.by_device.buckets : []"},
        {"type": "flatten", "fields": ["_device_buckets"], "as": ["_device_bucket"]},
        {"type": "formula", "as": "device_name", "expr": "datum._device_bucket.key"},
        {"type": "formula", "as": "_port_buckets",
          "expr": "datum._device_bucket.by_port && datum._device_bucket.by_port.buckets ? datum._device_bucket.by_port.buckets : []"},
        {"type": "flatten", "fields": ["_port_buckets"], "as": ["_port_bucket"]},
        {"type": "formula", "as": "_top_src",
          "expr": "datum._port_bucket && datum._port_bucket.latest && datum._port_bucket.latest.hits && datum._port_bucket.latest.hits.hits && datum._port_bucket.latest.hits.hits[0] ? datum._port_bucket.latest.hits.hits[0]._source : null"},
        {"type": "formula", "as": "port_id",
          "expr": "datum._top_src && datum._top_src.sdvn && datum._top_src.sdvn.device && datum._top_src.sdvn.device.value ? datum._top_src.sdvn.device.value.id : null"},
        {"type": "formula", "as": "port_value",
          "expr": "datum._top_src && datum._top_src.sdvn && datum._top_src.sdvn.device && datum._top_src.sdvn.device.value ? datum._top_src.sdvn.device.value.i_value : null"},
        // Extract numeric port id from the string 'port-N-operation-status'.
        // prefix length 5 = |port-|; suffix = |-operation-status|.
        {"type": "formula", "as": "_suffix_idx",
          "expr": "datum.port_id ? indexof(datum.port_id, '-operation-status') : -1"},
        {"type": "formula", "as": "port_num",
          "expr": "datum.port_id && indexof(datum.port_id, 'port-') === 0 && datum._suffix_idx > 5 ? substring(datum.port_id, 5, datum._suffix_idx) : null"},
        {"type": "filter", "expr": "datum.port_num != null"},
        // Composite key for joining declared ports back to their measured value.
        {"type": "formula", "as": "device_port_key",
          "expr": "datum.device_name + '|' + datum.port_num"}
      ]
    },

    // -- AGGREGATION DECLS: one row per declared upstream or downstream port.
    //    Built as two intermediate flattens (one per direction) + a combined union —
    //    Vega expressions cannot concat/tag two arrays in a single formula.
    {
      "name": "_agg_upstream_decls",
      "source": "manual_names",
      "transform": [
        {"type": "filter", "expr": "datum.role === 'aggregation'"},
        {"type": "flatten", "fields": ["upstream_ports"], "as": ["_decl"]},
        {"type": "formula", "as": "agg_name",  "expr": "datum.name"},
        {"type": "formula", "as": "direction", "expr": "'upstream'"},
        {"type": "formula", "as": "port",      "expr": "datum._decl.port"},
        {"type": "formula", "as": "neighbor",  "expr": "datum._decl.neighbor"}
      ]
    },
    {
      "name": "_agg_downstream_decls",
      "source": "manual_names",
      "transform": [
        {"type": "filter", "expr": "datum.role === 'aggregation'"},
        {"type": "flatten", "fields": ["downstream_ports"], "as": ["_decl"]},
        {"type": "formula", "as": "agg_name",  "expr": "datum.name"},
        {"type": "formula", "as": "direction", "expr": "'downstream'"},
        {"type": "formula", "as": "port",      "expr": "datum._decl.port"},
        {"type": "formula", "as": "neighbor",  "expr": "datum._decl.neighbor"}
      ]
    },

    // -- AGGREGATION DOWN EDGES: one row per DOWN declared port on an aggregation.
    //    Union of upstream + downstream decls, joined to aggregation_states via
    //    the composite (device, port) key, filtered to is_down === 1.
    {
      "name": "aggregation_down_edges",
      "source": ["_agg_upstream_decls", "_agg_downstream_decls"],
      "transform": [
        {"type": "formula", "as": "device_port_key",
          "expr": "datum.agg_name + '|' + datum.port"},
        {"type": "lookup", "from": "aggregation_states",
          "key": "device_port_key", "fields": ["device_port_key"], "as": ["_agg_state"]},
        {"type": "formula", "as": "port_value",
          "expr": "datum._agg_state ? datum._agg_state.port_value : null"},
        {"type": "formula", "as": "is_down",
          "expr": "datum.port_value === PORT_DOWN_VALUE ? 1 : 0"},
        {"type": "filter", "expr": "datum.is_down === 1"},
        {"type": "formula", "as": "_edge_key",
          "expr": "datum.agg_name + '|' + datum.direction + '|' + (datum.neighbor != null ? datum.neighbor : '')"}
      ]
    },

    // -- KNOWN DOWN EDGES: subset used by indata() membership test on link marks.
    {
      "name": "aggregation_known_down_edges",
      "source": "aggregation_down_edges",
      "transform": [
        {"type": "filter", "expr": "datum.neighbor != null && datum.neighbor !== ''"}
      ]
    },

    // -- ORPHAN FLAGS: per-device counts of DOWN ports with unknown neighbors.
    //    Used to flash the aggregation NODE itself when we can't pick a link.
    {
      "name": "aggregation_orphan_flags",
      "source": "aggregation_down_edges",
      "transform": [
        {"type": "formula", "as": "_is_orph_up",
          "expr": "datum.direction === 'upstream' && (datum.neighbor == null || datum.neighbor === '') ? 1 : 0"},
        {"type": "formula", "as": "_is_orph_dn",
          "expr": "datum.direction === 'downstream' && (datum.neighbor == null || datum.neighbor === '') ? 1 : 0"},
        {"type": "aggregate",
          "groupby": ["agg_name"],
          "fields": ["_is_orph_up", "_is_orph_dn"],
          "ops": ["sum", "sum"],
          "as": ["orphan_upstream_down", "orphan_downstream_down"]}
      ]
    },
    // -- SLAVE NODES: inferred from the PTP poller data --

    // Inferring the hierarchy from slaves to masters
    {
      "name": "nodes_slaves",
      "source": "source_hits",
      "transform": [
        // Project generates a dataset out of fields provided, grooming the data further into id, parent, status, and status value. Id and parent are required keywords of vega.
        // keep gm_id in the projection so we can compare each host's reported GM against the master's majority GM below.
        {"type": "project", "fields": ["slave_id", "master_id", "gm_id", "ptp_status", "status_value", "device_name", "device_type", "reported_master_side"], "as": ["id", "parent", "gm_id", "ptp_status", "status_value", "device_name", "device_type", "master_side"]},
        // Hardcode these entities as slaves for easier styling later
        {"type": "formula", "as": "type", "expr": "'slave'"}
      ,
      {"type": "lookup", "from": "filter_probe_ptp", "key": "key", "fields": ["id"], "as": ["_filter_match"], "default": null},
      {"type": "formula", "as": "in_filter", "expr": "datum._filter_match != null"},
      // look up the master's majority GM via the slave's parent (= master_id), then flag this slave if its reported gm_id differs from the majority winner.
      {"type": "lookup", "from": "master_majority_gm", "key": "master_id", "fields": ["parent"], "as": ["_majority"], "default": null},
      {"type": "formula", "as": "is_minority_gm", "expr": "datum.gm_id != null && datum._majority && datum._majority.majority_gm_id != null && datum.gm_id !== datum._majority.majority_gm_id"}]
    },
    // -- MASTER NODES: inferred from slave parent references --
    // If a slave is connected to a master, then the master must exist (inferred)
    // Manually create a node if so.
    {
      "name": "nodes_masters",
      "source": "source_hits",
      "transform": [
        // drop gm_id from the aggregate; the master's GM is decided by majority vote (looked up below) instead of an arbitrary max() across host reports.
        {"type": "aggregate", "groupby": ["master_id"], "fields": ["status_value", "reported_gm_side", "reported_gm_side", "is_unconverged", "mac_norm_gm"], "ops": ["max", "max", "min", "sum", "max"], "as": ["status_value", "master_side", "gm_side_min", "unconverged_subtree", "reported_gm_mac"]},
        // look up the master's majority GM (chosen by host count). The winner becomes gm_id; majority_count/total_count are kept on the row for the master tooltip.
        {"type": "lookup", "from": "master_majority_gm", "key": "master_id", "fields": ["master_id"], "as": ["_maj"], "default": null},
        {"type": "formula", "as": "gm_id", "expr": "datum._maj ? datum._maj.majority_gm_id : null"},
        {"type": "formula", "as": "majority_count", "expr": "datum._maj ? datum._maj.majority_count : 0"},
        {"type": "formula", "as": "total_count", "expr": "datum._maj ? datum._maj.total_count : 0"},
        // master-level "has dissent" flag so the node fill and tooltip can react to subtree disagreement.
        {"type": "formula", "as": "has_minority_subtree", "expr": "datum.total_count > datum.majority_count"},
        // Determine the masters parent (GM or Root). If the reported master is the same as GM, then its a GM.
        {"type": "formula", "as": "parent", "expr": "(datum.gm_id && datum.gm_id != datum.master_id) ? datum.gm_id : 'GLOBAL_ROOT'"},
        // Format into id's, parent, and status value like we did for slaves
        {"type": "project", "fields": ["master_id", "parent", "status_value", "master_side", "gm_side_min", "unconverged_subtree", "reported_gm_mac", "majority_count", "total_count", "has_minority_subtree"], "as": ["id", "parent", "status_value", "master_side", "gm_side_min", "unconverged_subtree", "reported_gm_mac", "majority_count", "total_count", "has_minority_subtree"] },
        // Type as GM or Master based on if its connected to Global Root or not.
        {"type": "formula", "as": "type", "expr": "datum.parent === 'GLOBAL_ROOT' ? 'grandmaster' : 'master'"},
        // Nulling device name/type since I don't have them yet in this dataset.
        {"type": "formula", "as": "device_name", "expr": "null"},
        {"type": "formula", "as": "device_type", "expr": "null"}
      ]
    },
    {
      "name": "match_counts_by_parent",
      "source": "nodes_slaves",
      "transform": [
        {"type": "filter", "expr": "datum.in_filter"},
        {"type": "aggregate", "groupby": ["parent"], "ops": ["count"], "as": ["match_count"]}
      ]
    },
    {
      "name": "match_counts_by_grandparent",
      "source": "nodes_slaves",
      "transform": [
        {"type": "filter", "expr": "datum.in_filter"},
        {"type": "lookup", "from": "nodes_masters", "key": "id", "fields": ["parent"], "as": ["_master_row"], "default": null},
        {"type": "formula", "as": "_gm_id", "expr": "datum._master_row ? datum._master_row.parent : null"},
        {"type": "filter", "expr": "datum._gm_id != null"},
        {"type": "aggregate", "groupby": ["_gm_id"], "ops": ["count"], "as": ["match_count"]}
      ]
    },
    // -- GRANDMASTER NODES: inferred from master GM references --
    // Inferring just like we did for masters.
    {
      "name": "nodes_gms",
      "source": "source_hits",
      "transform": [
        // Create new node here only if the gm_id is unique/doesn't match an existing master.
        {"type": "filter", "expr": "datum.gm_id != null && datum.gm_id != datum.master_id"},
        // Deduplicate as was done for masters.
        {"type": "aggregate", "groupby": ["gm_id"], "fields": ["status_value", "is_unconverged"], "ops": ["max", "sum"], "as": ["status_value", "unconverged_subtree"]},

        // Format into the expected vega type (ID)
        {"type": "project", "fields": ["gm_id", "status_value", "unconverged_subtree"], "as": ["id", "status_value", "unconverged_subtree"]},

        // Link GM's to root
        {"type": "formula", "as": "parent", "expr": "'GLOBAL_ROOT'"},
        {"type": "formula", "as": "type", "expr": "'grandmaster'"},
        {"type": "formula", "as": "device_name", "expr": "null"},
        {"type": "formula", "as": "device_type", "expr": "null"}
      ]
    },

    {
      "name": "group_active_parents",
      "source": "nodes_masters",
      "transform": [
        // 1. Map the active masters to their manual groups
        {
          "type": "lookup", "from": "manual_names", "key": "name", "fields": ["id"], "as": ["manual"]
        },
        {"type": "formula", "as": "group_id", "expr": "datum.manual ? datum.manual.group_id : null"},

        // 2. Filter out orphaned masters that don't have a group or a real GM parent
        {"type": "filter", "expr": "datum.group_id != null && datum.parent != 'GLOBAL_ROOT'"},

        // 3. Aggregate by group_id to capture which clock is currently master
        {
          "type": "aggregate", 
          "groupby": ["group_id"], 
          "fields": ["parent"], 
          "ops": ["max"], // Grabs the valid active parent for the group
          "as": ["best_parent"]
        }
      ]
    },
    // -- PASSIVE GRANDMASTERS: manually-defined GMs with no live telemetry --
    {
      "name": "passive_gms",
      "source": "manual_names",
      "transform": [
        {"type": "filter", "expr": "datum.role === 'grandmaster'"},
        {"type": "aggregate", "groupby": ["name"], "fields": ["group_id"], "ops": ["max"], "as": ["group_id"]},
        {"type": "formula", "as": "id", "expr": "datum.name"},
        {"type": "formula", "as": "type", "expr": "'grandmaster'"},
        {"type": "formula", "as": "parent", "expr": "'GLOBAL_ROOT'"}
      ]
    },

    // -- PASSIVE MASTERS: manually-defined masters with no live telemetry --
    {
      "name": "passive_masters",
      "source": "manual_names",
      "transform": [
        {"type": "filter", "expr": "datum.role === 'master'"},
        {"type": "aggregate", "groupby": ["name"], "fields": ["group_id"], "ops": ["max"], "as": ["group_id"]},
        {"type": "formula", "as": "id", "expr": "datum.name"},
        {"type": "formula", "as": "type", "expr": "'master'"},

        // This looks into the passive_gms dataset we just built above.
        // It grabs the ID of the GM that shares the same group_id.
        {
          "type": "lookup",
          "from": "passive_gms",
          "key": "group_id",
          "fields": ["group_id"],
          "as": ["gm_match"]
        },

        // Use that GM's ID as the parent. If it fails, fallback to root.
        {"type": "formula", "as": "parent", "expr": "datum.gm_match ? datum.gm_match.id : 'GLOBAL_ROOT'"}
      ]
    },

    // -- PASSIVE AGGREGATIONS: manually-defined aggregation switches.
    //    Parented to the GM named by `gm_group_id` (optional). When absent,
    //    falls back to GLOBAL_ROOT so the node still renders. BCs in the same
    //    `group_id` are re-parented onto the aggregation in the tree transform.
    {
      "name": "passive_aggregations",
      "source": "manual_names",
      "transform": [
        {"type": "filter", "expr": "datum.role === 'aggregation'"},
        {"type": "aggregate",
          "groupby": ["name"],
          "fields": ["group_id", "gm_group_id", "side"],
          "ops": ["max", "max", "max"],
          "as": ["group_id", "gm_group_id", "side"]},
        {"type": "formula", "as": "id",   "expr": "datum.name"},
        {"type": "formula", "as": "type", "expr": "'aggregation'"},
        // Composite key: masters will re-parent to the agg whose
        // (group_id, side) pair matches their own.
        {"type": "formula", "as": "match_key",
          "expr": "(datum.group_id != null ? datum.group_id : '') + '|' + (datum.side != null ? datum.side : '')"},
        // Project side -> master_side so GM->agg links pick up RED/BLUE
        // via the same stroke signal that already handles GM->master links.
        {"type": "formula", "as": "master_side", "expr": "datum.side"},
        {"type": "lookup", "from": "passive_gms",
          "key": "group_id", "fields": ["gm_group_id"], "as": ["_gm_match"]},
        {"type": "formula", "as": "parent",
          "expr": "datum._gm_match ? datum._gm_match.id : 'GLOBAL_ROOT'"}
      ]
    },

    // -- AGG UPSTREAM MAC BINDINGS: one row per (gm_mac, agg_id).

    //    Flattens manual_names[role=grandmaster].ids[] and emits one row
    //    per GM MAC with its declared side. Keyed by normalized gm_mac so
    //    agg_upstream_mac_bindings can attach the per-port side that the
    //    AGG->GM edge should paint with.
    {
      "name": "gm_mac_sides",
      "source": "manual_names",
      "transform": [
        {"type": "filter", "expr": "datum.role === 'grandmaster'"},
        {"type": "formula", "as": "_ids",
          "expr": "isArray(datum.ids) ? datum.ids : []"},
        {"type": "filter", "expr": "length(datum._ids) > 0"},
        {"type": "flatten", "fields": ["_ids"], "as": ["_id"]},
        {"type": "filter",
          "expr": "datum._id && datum._id.mac != null && datum._id.mac !== ''"},
        // Same normalize formula as agg_upstream_mac_bindings so keys match.
        {"type": "formula", "as": "gm_mac",
          "expr": "length(datum._id.mac) > 17 ? lower(substring(datum._id.mac,0,2))+':'+lower(substring(datum._id.mac,3,5))+':'+lower(substring(datum._id.mac,6,8))+':'+lower(substring(datum._id.mac,15,17))+':'+lower(substring(datum._id.mac,18,20))+':'+lower(substring(datum._id.mac,21,23)) : lower(replace(datum._id.mac, '-', ':'))"},
        {"type": "formula", "as": "gm_mac_side", "expr": "datum._id.side"},
        {"type": "project", "fields": ["gm_mac", "gm_mac_side"], "as": ["gm_mac", "gm_mac_side"]}
      ]
    },

    //    Flattens passive_aggregations.upstream_ports and normalizes each
    //    declared mac to the same canonical form used on reported_gm_mac.
    //    Used by the tree pipeline to re-parent masters directly onto the
    //    AGG whose upstream port physically carries the reported GM MAC.
    {
      "name": "agg_upstream_mac_bindings",
      "source": "passive_aggregations",
      "transform": [
        // Flatten-guard: coalesce missing upstream_ports to [] and drop
        // rows with no declared ports (matches manual_names_flat pattern).
        {"type": "formula", "as": "_ports",
          "expr": "isArray(datum.upstream_ports) ? datum.upstream_ports : []"},
        {"type": "filter", "expr": "length(datum._ports) > 0"},
        {"type": "flatten", "fields": ["_ports"], "as": ["_port"]},
        // Only ports that declare a MAC participate in the binding.
        {"type": "filter",
          "expr": "datum._port && datum._port.mac != null && datum._port.mac !== ''"},
        // Normalize the declared MAC to match mac_norm_gm (source_hits):
        // EUI-64 (>17 chars) → 6-byte colon MAC via substring slicing;
        // else lowercase + replace '-' with ':'.
        {"type": "formula", "as": "gm_mac",
          "expr": "length(datum._port.mac) > 17 ? lower(substring(datum._port.mac,0,2))+':'+lower(substring(datum._port.mac,3,5))+':'+lower(substring(datum._port.mac,6,8))+':'+lower(substring(datum._port.mac,15,17))+':'+lower(substring(datum._port.mac,18,20))+':'+lower(substring(datum._port.mac,21,23)) : lower(replace(datum._port.mac, '-', ':'))"},
        {"type": "formula", "as": "agg_id", "expr": "datum.id"},
        // attach the side of this specific GM MAC so the AGG->GM
        // edge can paint with the port's color rather than the AGG's side.
        {"type": "lookup", "from": "gm_mac_sides", "key": "gm_mac",
          "fields": ["gm_mac"], "as": ["_gm_port_match"]},
        {"type": "formula", "as": "gm_mac_side",
          "expr": "datum._gm_port_match ? datum._gm_port_match.gm_mac_side : null"},
        {"type": "project", "fields": ["gm_mac", "agg_id", "gm_mac_side"], "as": ["gm_mac", "agg_id", "gm_mac_side"]}
      ]
    },

    // Per-AGG upstream-port side table:
    //    Flattens passive_aggregations.upstream_ports[] and emits one row
    //    per (agg, neighbor GM) with the side of that specific upstream
    //    port's MAC. Keyed by agg_id + '|' + neighbor so the tree lookup
    //    can resolve the AGG->GM edge color using the AGG's tree parent
    //    (which is the GM name, matching the neighbor field).
    {
      "name": "agg_parent_port_sides",
      "source": "passive_aggregations",
      "transform": [
        {"type": "formula", "as": "_ports",
          "expr": "isArray(datum.upstream_ports) ? datum.upstream_ports : []"},
        {"type": "filter", "expr": "length(datum._ports) > 0"},
        {"type": "flatten", "fields": ["_ports"], "as": ["_port"]},
        {"type": "filter",
          "expr": "datum._port && datum._port.mac != null && datum._port.mac !== '' && datum._port.neighbor != null"},
        // Same MAC-normalize formula used in agg_upstream_mac_bindings.
        {"type": "formula", "as": "gm_mac",
          "expr": "length(datum._port.mac) > 17 ? lower(substring(datum._port.mac,0,2))+':'+lower(substring(datum._port.mac,3,5))+':'+lower(substring(datum._port.mac,6,8))+':'+lower(substring(datum._port.mac,15,17))+':'+lower(substring(datum._port.mac,18,20))+':'+lower(substring(datum._port.mac,21,23)) : lower(replace(datum._port.mac, '-', ':'))"},
        {"type": "lookup", "from": "gm_mac_sides", "key": "gm_mac",
          "fields": ["gm_mac"], "as": ["_gm_port_match"]},
        {"type": "formula", "as": "gm_mac_side",
          "expr": "datum._gm_port_match ? datum._gm_port_match.gm_mac_side : null"},
        {"type": "formula", "as": "_agg_port_key",
          "expr": "datum.id + '|' + datum._port.neighbor"},
        {"type": "project", "fields": ["_agg_port_key", "gm_mac_side"],
          "as": ["_agg_port_key", "gm_mac_side"]}
      ]
    },

    // Config-based AGG->GM port side:
    //   Fallback when no master is reporting a current GM MAC. Uses the
    //   gm_mac_side already attached to each row of
    //   agg_upstream_mac_bindings (build 53) and aggregates it by AGG.
    //   Answers "which side is any of this AGG's declared upstream
    //   ports pointing at, according to the GM's ids list".
    {
      "name": "agg_config_gm_sides",
      "source": "agg_upstream_mac_bindings",
      "transform": [
        {"type": "filter", "expr": "datum.gm_mac_side != null"},
        {"type": "aggregate", "groupby": ["agg_id"],
          "fields": ["gm_mac_side"], "ops": ["max"], "as": ["config_gm_side"]}
      ]
    },

    // -- SYNTHETIC ROOT: required by Vega stratify transform --

    // Purely synthetic root, all tree graphs require one
    {
      "name": "node_root",
      "values": [{"id": "GLOBAL_ROOT", "parent": null, "type": "root", "status_value": 0, "device_name": null, "device_type": null}] 
    },


    // Tree Linking
    {
      "name": "tree",
      "source": ["node_root", "nodes_gms", "nodes_masters", "nodes_slaves", "passive_gms", "passive_masters", "passive_aggregations"],
      "transform": [
        {
          "type": "formula",
          "expr": "zipper_lanes + zipper_offset", 
          "as": "render_trigger"
        },
        {
          "type": "aggregate", 
          "groupby": ["id"], 
          "fields": ["parent", "type", "status_value", "ptp_status", "device_name", "device_type", "master_side", "gm_side_min", "unconverged_subtree", "is_minority_gm", "majority_count", "total_count", "has_minority_subtree", "gm_id"], 
          "ops": ["max", "max", "max", "max", "max", "max", "max", "min", "max", "max", "max", "max", "max", "max"], 
          "as": ["parent", "type", "status_value", "ptp_status", "device_name", "device_type", "master_side", "gm_side_min", "unconverged_subtree", "is_minority_gm", "majority_count", "total_count", "has_minority_subtree", "gm_id"]
        },
        {"type": "formula", "as": "final_status", "expr": "datum.ptp_status ? datum.ptp_status : (datum.status_value === 1 ? 'Unconverged Descendants' : 'Converged')"},

        // 1. LOOKUPS
        {
          "type": "lookup", "from": "manual_names", "key": "name", "fields": ["id"],
          "as": ["manual_data"]
        },
        {
          "type": "lookup", "from": "clock_states", "key": "device_name", "fields": ["id"],
          "as": ["clock_data"]
        },

        {
          "type": "formula",
          "as": "tree_sort_key",
          "expr": "(datum.manual_data ? 'A_' : 'Z_') + (datum.manual_data && datum.manual_data.group_id ? datum.manual_data.group_id : 'ZZZ_UNGROUPED') + '_' + datum.display_name"
        },

        // Ensure group_sort_key is still present for your tethering logic later
        {
          "type": "formula",
          "as": "group_sort_key",
          "expr": "datum.manual_data && datum.manual_data.group_id ? datum.manual_data.group_id : 'ZZZ_UNGROUPED'"
        },

        // This safely handles nodes that have no manual definition
        {
          "type": "formula",
          "as": "safe_group_id",
          "expr": "datum.manual_data ? datum.manual_data.group_id : null"
        },

        // 
        // Use safe group ID that was just created
        {
          "type": "lookup", 
          "from": "group_active_parents", 
          "key": "group_id", 
          "fields": ["safe_group_id"],
          "as": ["active_group_gm"]
        },

        {
          "type": "lookup", 
          "from": "passive_gms", 
          "key": "group_id", 
          "fields": ["safe_group_id"],
          "as": ["passive_group_gm"]
        },

        // Composite key for side-aware agg matching. Masters only re-parent
        // onto the agg whose (group_id, side) pair matches their own — so
        // RED masters go to the RED agg, BLUE masters to the BLUE agg.
        {
          "type": "formula",
          "as": "master_match_key",
          "expr": "(datum.safe_group_id != null ? datum.safe_group_id : '') + '|' + ((datum.manual_data && isArray(datum.manual_data.ids) && length(datum.manual_data.ids) > 0 && datum.manual_data.ids[0].side != null) ? datum.manual_data.ids[0].side : (datum.master_side != null ? datum.master_side : ''))"
        },

        // Direct MAC binding: each passive_aggregation declares upstream_ports
        // with the specific GM-port MACs it physically connects to. If the
        // reported GM MAC matches one of those MACs, that agg IS the active
        // path — wins over side-based match_key.
        {
          "type": "lookup",
          "from": "agg_upstream_mac_bindings",
          "key": "gm_mac",
          "fields": ["reported_gm_mac"],
          "as": ["_agg_mac_match"]
        },

        // tree<->live_agg_gm_sides cycle broken. Stroke reads
        //   link-level fields computed in the `links` data source; the
        //   tree only needs the AGG's own side for diagnostics.
        {"type": "lookup", "from": "passive_aggregations", "key": "id",
          "fields": ["id"], "as": ["_pa_self_match"]},
        {"type": "formula", "as": "agg_config_side",
          "expr": "datum._pa_self_match ? datum._pa_self_match.side : null"},

        // Look up any passive_aggregation whose (group_id, side) matches this
        // node. If found, masters in the same group+side re-parent to the agg.
        {
          "type": "lookup",
          "from": "passive_aggregations",
          "key": "match_key",
          "fields": ["master_match_key"],
          "as": ["_agg_match"]
        },

        // Bring per-agg orphan-port-down scalars onto the aggregation node itself.
        {
          "type": "lookup",
          "from": "aggregation_orphan_flags",
          "key": "agg_name",
          "fields": ["id"],
          "as": ["agg_orphan"]
        },

        // Force explicit master clocks to find grandmaster
          // 1. If a passive_aggregation exists for this master's group, parent
          //    becomes the aggregation's id (interposes agg between GM and BC).
          // 2. Else: active_group_gm → passive_group_gm → reported parent.
        {
          "type": "formula",
          "as": "parent",
          "expr": "datum.manual_data && datum.manual_data.role === 'master' ? (datum._agg_mac_match ? datum._agg_mac_match.agg_id : (datum._agg_match ? datum._agg_match.id : (datum.active_group_gm ? datum.active_group_gm.best_parent : (datum.passive_group_gm ? datum.passive_group_gm.id : datum.parent)))) : datum.parent"
        },
        // D. FORCE THE TYPE: Protect against the max merge bug
        {
          "type": "formula",
          "as": "type",
          "expr": "datum.manual_data && datum.manual_data.role ? datum.manual_data.role : datum.type"
        },

        // 2. LOGIC FLAGS
        {
          "type": "formula",
          "as": "display_name",
          "expr": "(datum.type === 'grandmaster' || datum.type === 'master') ? (datum.manual_data ? datum.manual_data.name : (datum.clock_data ? datum.clock_data.device_name : datum.id)) : datum.id"
        },
        {
          "type": "formula",
          "as": "group_sort_key",
          "expr": "datum.manual_data ? datum.manual_data.group_id : (datum.type === 'grandmaster' ? datum.id : datum.type === 'master' ? 'ZZZ_UNKNOWN' : datum.id)"
        },
        {"type": "formula", "as": "group_id", "expr": "datum.group_sort_key"},

        // If it has clock_data, trust it. If not, check if it has a status_value from the active telemetry. 
        // If status_value is null, it means it was generated purely by the manual list, so it MUST be passive.
        {
          "type": "formula", 
          "as": "is_passive", 
          "expr": "datum.clock_data ? datum.clock_data.is_passive : (datum.status_value == null)"
        },

        {
          "type": "formula",
          "as": "has_no_port_data",
          "expr": "(datum.type === 'grandmaster' || datum.type === 'master') && (!datum.clock_data || (datum.clock_data.port_1 === 'NO DATA' && datum.clock_data.port_2 === 'NO DATA' && datum.clock_data.port_3 === 'NO DATA' && datum.clock_data.port_4 === 'NO DATA') || (datum.clock_data.port_1 === 'Unknown' && datum.clock_data.port_2 === 'Unknown' && datum.clock_data.port_3 === 'Unknown' && datum.clock_data.port_4 === 'Unknown'))"
        },
        {
          "type": "formula",
          "as": "sort_weight",
          "expr": "datum.type === 'slave' ? 2 : (datum.manual_data && datum.group_sort_key !== 'ZZZ_UNKNOWN' ? 0 : 1)"
        },

        // --- 2. THE BRUTE FORCE SORT ---
        // Priority 1: Weight (forces all 1s to the end)
        // Priority 2: Alphabetize by Group ID (A -> G)
        // Priority 3: Alphabetize by Name (as a tie-breaker)
        {
          "type": "collect",
          "sort": {
            "field": ["sort_weight", "group_sort_key", "display_name"],
            "order": ["ascending", "ascending", "ascending"]
          }
        },
{
          "type": "formula",
          "as": "parent",
          "expr": "datum.parent ? datum.parent : (datum.type === 'grandmaster' || (datum.manual_data && datum.manual_data.role === 'grandmaster') ? 'GLOBAL_ROOT' : datum.parent)"
        },
        // 2. BUILD TREE LAYOUT
        {"type": "stratify", "key": "id", "parentKey": "parent"},
        {
          "type": "tree", 
          "method": {"signal": "layout"}, 
          "separation": true,
          "size": [{"signal": "max(width * zoom * 0.7 / zipper_lanes, width * zoom * 0.3)"}, {"signal": "(height - 100) * zoom"}], 
          "as": ["x", "y", "depth", "children"]
        },

        // -- GROUP GAP SYSTEM --
        // Injects GROUP_PADDING pixels of spacing between sibling groups at each tree tier.
        // Works in numbered bridge steps, then collapses into a single x-shift per node type.
        //
        // STEP 0: Snapshot raw tree x so the shift formula always reads the original
        //         layout position, not a stale re-run result.
        {"type": "formula", "as": "raw_tree_x", "expr": "datum.x"},


        // STEP 1: Count group-boundary crossings at each depth level.
        //         A boundary = two adjacent nodes (same depth) have different parents.
        //         boundaries_before_me = cumulative count scanning left-to-right.
        {"type": "window", "sort": {"field": "x", "order": "ascending"}, "groupby": ["depth"], "ops": ["lag"], "fields": ["parent"], "as": ["prev_node_parent"]},
        {"type": "formula", "as": "is_group_boundary", "expr": "datum.prev_node_parent != null && datum.prev_node_parent !== datum.parent ? 1 : 0"},
        {"type": "window", "sort": {"field": "x", "order": "ascending"}, "groupby": ["depth"], "ops": ["sum"], "fields": ["is_group_boundary"], "as": ["boundaries_before_me"]},

        // 2. Slave <-> Master bridge:
        //    - slaves get their parent master's depth_bc (parent_master_boundaries)
        //    - masters get the max slave depth_bc among their children (child_slave_boundaries)
        {"type": "formula", "as": "master_slave_link_key", "expr": "datum.type === 'slave' ? 'M:' + datum.parent : (datum.type === 'master' ? 'M:' + datum.id : '_:' + datum.id)"},
        {"type": "formula", "as": "slave_boundary_count", "expr": "datum.type === 'slave' ? datum.boundaries_before_me : null"},
        {"type": "formula", "as": "master_boundary_count", "expr": "datum.type === 'master' ? datum.boundaries_before_me : null"},
        {"type": "joinaggregate", "groupby": ["master_slave_link_key"], "fields": ["slave_boundary_count", "master_boundary_count"], "ops": ["max", "max"], "as": ["child_slave_boundaries", "parent_master_boundaries"]},

        // 3. Master <-> GM bridge:
        //    - GMs get the mean of their masters' total boundary counts (gm_total_boundaries)
        {"type": "formula", "as": "gm_master_link_key", "expr": "datum.type === 'grandmaster' ? 'G:' + datum.id : (datum.type === 'master' ? 'G:' + datum.parent : '_:' + datum.id)"},
        {"type": "formula", "as": "master_total_boundaries", "expr": "datum.type === 'master' ? (datum.child_slave_boundaries != null ? datum.child_slave_boundaries : 0) + datum.boundaries_before_me : null"},
        {"type": "joinaggregate", "groupby": ["gm_master_link_key"], "fields": ["master_total_boundaries"], "ops": ["mean"], "as": ["gm_total_boundaries"]},


        // 3.75. GM-level cumulative-max bridge:
        //       GMs without masters (unnamed/not in manual_names) get gm_total_boundaries=null
        //       and stay static as GROUP_PADDING grows while named GMs shift right.
        //       Scan all GMs left→right by x, propagate a running max of gm_total_boundaries so
        //       unnamed GMs shift at least as much as the last named GM to their left,
        //       keeping them in their correct relative position.
        {"type": "formula", "as": "gm_boundary_value", "expr": "datum.type === 'grandmaster' ? datum.gm_total_boundaries : null"},
        {"type": "window", "sort": {"field": "x", "order": "ascending"}, "groupby": ["depth"], "ops": ["max"], "fields": ["gm_boundary_value"], "frame": [null, 0], "as": ["gm_cumulative_max_boundaries"]},

        // 3.5. Direct-GM slave cumulative-max bridge:
        //      Slaves at depth=2 sit alongside masters under the same GM.
        //      We scan left-to-right (by x) within each [depth, parent] group and
        //      compute a running max of masters' child_slave_boundaries values.
        //      A direct-to-GM slave picks up the cummax of all masters to its left,
        //      so it shifts by at least as much as the preceding master — keeping
        //      it in the correct relative position rather than drifting back into
        //      the master column.
        {"type": "formula", "as": "depth2_master_boundary_value", "expr": "datum.depth === 2 && datum.type === 'master' ? (datum.child_slave_boundaries != null ? datum.child_slave_boundaries : 0) : null"},
        {"type": "window", "sort": {"field": "x", "order": "ascending"}, "groupby": ["depth", "parent"], "ops": ["max"], "fields": ["depth2_master_boundary_value"], "frame": [null, 0], "as": ["depth2_master_cummax_boundaries"]},

        // 3.76. Parent-GM cummax propagation to depth-2 children:
        //       GMs broadcast their gm_cumulative_max_boundaries and gm_total_boundaries to all depth-2 children.
        //       Children of unnamed GMs (parent_gm_named_boundaries == null) use parent_gm_cummax_boundaries
        //       instead of boundaries_before_me so they shift in lockstep with the GM's inherited offset
        //       rather than the (smaller) raw boundary count at depth 2.
        {"type": "formula", "as": "gm_to_depth2_link_key", "expr": "datum.type === 'grandmaster' ? 'D1G:' + datum.id : (datum.depth === 2 ? 'D1G:' + datum.parent : '_D1G:' + datum.id)"},
        {"type": "joinaggregate", "groupby": ["gm_to_depth2_link_key"], "fields": ["gm_cumulative_max_boundaries", "gm_total_boundaries"], "ops": ["max", "max"], "as": ["parent_gm_cummax_boundaries", "parent_gm_named_boundaries"]}

        // 3.77. Global depth-2 master cummax:
        //       Scan ALL depth=2 masters left->right (no parent scoping) and accumulate
        //       the running max of master_total_boundaries. Unnamed-GM direct slaves
        //       read this value to ensure they shift at least as far as the rightmost
        //       named-GM master, not just as far as the (smaller) GM-level mean.
        {"type": "formula", "as": "depth2_global_master_total_val", "expr": "datum.depth === 2 && datum.type === 'master' ? datum.master_total_boundaries : null"},
        {"type": "window", "sort": {"field": "x", "order": "ascending"}, "groupby": ["depth"], "ops": ["max"], "fields": ["depth2_global_master_total_val"], "frame": [null, 0], "as": ["depth2_global_master_cummax"]},


        // STEP 4: Apply the x shift. Final per-type shift factors:
        //   grandmaster : gm_total_boundaries (or gm_cumulative_max_boundaries as fallback)
        //   master      : child_slave_boundaries + boundaries_before_me (or cummax for unnamed-GM children)
        //   slave d>=3  : boundaries_before_me + parent_master_boundaries
        //   slave d=2 (named GM)   : boundaries_before_me + depth2_master_cummax_boundaries
        //   slave d=2 (unnamed GM) : max(boundaries_before_me, depth2_global_master_cummax)
